 {"id":"jeffreysprompts.com-02u","title":"Build ChangelogAccordion for prompt detail pages","description":"**Details:**
- Shows version history when prompt.changelog exists
- Accordion expansion (collapsed by default)
- Lists changes chronologically (newest first)
- Version, date, and change description per entry

**Changelog Type (in types.ts):**
```typescript
interface PromptChange {
  version: string;
  date: string;
  changes: string[];
}

// On Prompt interface:
changelog?: PromptChange[];
```

**Implementation:**
```typescript
// apps/web/src/components/changelog-accordion.tsx

interface ChangelogAccordionProps {
  changelog: PromptChange[];
}

export function ChangelogAccordion({ changelog }: ChangelogAccordionProps) {
  const [expanded, setExpanded] = useState(false);

  if (!changelog?.length) return null;

  return (
    <div className='border-t pt-4 mt-4'>
      <button onClick={() => setExpanded(!expanded)} className='flex items-center gap-2'>
        <ChevronRight className={`size-4 transition ${expanded ? 'rotate-90' : ''}`} />
        <span className='font-medium'>What changed</span>
        <Badge variant='secondary'>{changelog.length} versions</Badge>
      </button>

      <AnimatePresence>
        {expanded && (
          <motion.div initial={{height:0}} animate={{height:'auto'}} exit={{height:0}}>
            <ul className='mt-4 space-y-4'>
              {changelog.map((entry) => (
                <li key={entry.version}>
                  <div className='flex items-center gap-2'>
                    <Badge>{entry.version}</Badge>
                    <span className='text-sm text-muted-foreground'>{entry.date}</span>
                  </div>
                  <ul className='mt-1 ml-4 list-disc'>
                    {entry.changes.map((change, i) => (
                      <li key={i} className='text-sm'>{change}</li>
                    ))}
                  </ul>
                </li>
              ))}
            </ul>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
```

